class Solution {
public:
    int superEggDrop(int k, int n) {
        vector<vector<int>> dp(k + 1, vector<int>(n + 1, 0));
        for (int i = 1; i <= k; i++) {
            for (int j = 1; j <= n; j++) {
                dp[i][j] = 1 + min(dp[i - 1][j - 1], dp[i][j - 1]);
                if (j == 1) dp[i][j] = 1;
                if (i == 1) dp[i][j] = j;
            }
        }
        return dp[k][n];
    }
};
